import { CUSTOM_ELEMENTS_SCHEMA, NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

// import { NgToastModule } from 'ng-angular-popup';
import { ToastrModule } from 'ngx-toastr';

import { AppRoutingModule } from './app-routing.module';
import { AppComponent } from './app.component';
import { ToolbarComponent } from './toolbar/toolbar.component';
import { MainComponent } from './main/main.component';
import { UserService } from './services/user.service';
import { HttpClientModule } from '@angular/common/http';
import { FormsModule, ReactiveFormsModule } from '@angular/forms';
import { ChatComponent } from './chat/chat.component';
import { TopicDialogComponent } from './topic-dialog/topic-dialog.component';
import { BrowserAnimationsModule } from '@angular/platform-browser/animations';
import { MatDialogModule } from '@angular/material/dialog';
import { DialogComponent } from './dialog/dialog.component';
import { RegisterComponent } from './register/register.component';
import { NotfoundComponent } from './notfound/notfound.component';



ToastrModule.forRoot({
  timeOut: 3000,            // Время отображения уведомления
  positionClass: 'toast-top-right',  // Позиция уведомления
  preventDuplicates: true,  // Запрещает дублирование уведомлений
  closeButton: true,        // Отображает кнопку для закрытия уведомления
  progressBar: true,        // Отображает полоску прогресса
})


@NgModule({
  declarations: [
    AppComponent,
    ToolbarComponent,
    MainComponent,
    ChatComponent,

    TopicDialogComponent,
    DialogComponent,
    RegisterComponent,
    NotfoundComponent    
  ],
  imports: [
    BrowserModule,
    AppRoutingModule,
    HttpClientModule,
    FormsModule,
    BrowserAnimationsModule,
    MatDialogModule,
    ReactiveFormsModule,

    // NgToastModule,

    ToastrModule.forRoot(),    
  ],
  providers: [UserService],
  bootstrap: [AppComponent],
  schemas: [CUSTOM_ELEMENTS_SCHEMA]
})
export class AppModule { }
